#!/usr/bin/env python3
import json
import os
import re
from datetime import datetime

# Helper to normalize date strings to YYYY-MM-DD
DATE_FMT = "%Y-%m-%d"

def norm_date(s):
    s = s.strip()
    # Try multiple common formats
    for fmt in ["%Y-%m-%d", "%d-%m-%Y", "%m/%d/%Y", "%Y/%m/%d", "%b %d, %Y", "%B %d, %Y", "%d %b %Y", "%d %B %Y"]:
        try:
            return datetime.strptime(s, fmt).strftime(DATE_FMT)
        except Exception:
            pass
    # Fallback: try to detect YYYY-MM-DD by regex
    m = re.search(r"(\d{4}-\d{2}-\d{2})", s)
    if m:
        return m.group(1)
    raise ValueError(f"Unrecognized date format: {s}")

# Parse different file formats into list of {start, end}

def parse_file(path):
    with open(path, 'r', encoding='utf-8') as f:
        content = f.read().strip()
    # Try JSON first
    try:
        data = json.loads(content)
        # Support formats:
        # 1) {"availability": [{"start": ..., "end": ...}, ...]}
        # 2) [{"start": ..., "end": ...}, ...]
        # 3) {"busy": [{"start": ..., "end": ...}]} -> convert to availability by inverting if ranges provided? If busy is given, we cannot invert without a bounding calendar. We'll assume it provides availability.
        if isinstance(data, dict):
            if 'availability' in data and isinstance(data['availability'], list):
                ranges = data['availability']
            elif 'free' in data and isinstance(data['free'], list):
                ranges = data['free']
            elif 'available' in data and isinstance(data['available'], list):
                ranges = data['available']
            elif 'schedule' in data and isinstance(data['schedule'], list):
                # might be entries like {"type":"free","start":...,"end":...}
                ranges = [r for r in data['schedule'] if str(r.get('type','')).lower() in ('free','available')]
            else:
                # if dict of name -> ranges
                # e.g., {"alice": [{...}, ...]}
                if len(data) == 1 and isinstance(next(iter(data.values())), list):
                    ranges = next(iter(data.values()))
                else:
                    ranges = []
        elif isinstance(data, list):
            ranges = data
        else:
            ranges = []
        out = []
        for r in ranges:
            start = r.get('start') if isinstance(r, dict) else None
            end = r.get('end') if isinstance(r, dict) else None
            if start and end:
                try:
                    out.append({
                        'start': norm_date(start),
                        'end': norm_date(end)
                    })
                except Exception:
                    continue
        if out:
            return out
    except Exception:
        pass

    # Not JSON: parse line-based formats
    # Supported patterns:
    # - Lines "YYYY-MM-DD to YYYY-MM-DD"
    # - CSV: start,end
    # - Semicolon or pipe separated: start;end or start|end
    # - Markdown list: - start - end or similar with labels
    out = []
    for line in content.splitlines():
        line = line.strip()
        if not line:
            continue
        # Remove bullets or labels
        line_clean = re.sub(r"^[\-*\d\.\)]\s*", "", line)
        line_clean = re.sub(r"(?i)^(start|from)\s*:\s*", "", line_clean)
        # Patterns
        if ' to ' in line_clean:
            parts = line_clean.split(' to ')
            if len(parts) == 2:
                try:
                    s = norm_date(parts[0])
                    e = norm_date(parts[1])
                    out.append({'start': s, 'end': e})
                    continue
                except Exception:
                    pass
        for sep in [',', ';', '|', '\t']:
            if sep in line_clean:
                parts = [p.strip() for p in line_clean.split(sep) if p.strip()]
                if len(parts) >= 2:
                    try:
                        s = norm_date(parts[0])
                        e = norm_date(parts[1])
                        out.append({'start': s, 'end': e})
                        break
                    except Exception:
                        pass
        # Try regex for two dates on a line
        m = re.findall(r"\d{4}-\d{2}-\d{2}", line_clean)
        if len(m) >= 2:
            out.append({'start': m[0], 'end': m[1]})
    return out

friends = ['alice','bob','charlie','dana']
input_files = {f: f"/app/{f}_schedule.txt" for f in friends}
all_availability = {}
for f in friends:
    path = input_files[f]
    if not os.path.exists(path):
        raise FileNotFoundError(f"Missing schedule file: {path}")
    ranges = parse_file(path)
    # Ensure correct structure: list of dicts with start/end
    clean = []
    for r in ranges:
        try:
            s = norm_date(r['start'])
            e = norm_date(r['end'])
            clean.append({'start': s, 'end': e})
        except Exception:
            continue
    all_availability[f] = clean

out_path = "/app/all_availability.json"
