DATE_FMT = '%Y-%m-%d'

def d(s):
    y,m,da = map(int, s.split('-'))
    return date(y,m,da)

def ds(dt):
    return dt.strftime(DATE_FMT)

def merge_ranges(ranges):
    if not ranges:
        return []
    ranges = sorted(ranges, key=lambda r: r[0])
    out = [ranges[0]]
    for s,e in ranges[1:]:
        ps,pe = out[-1]
        if s <= pe + timedelta(days=1):
            out[-1] = (ps, max(pe, e))
        else:
            out.append((s,e))
    return out

def invert_within(year_start, year_end, blocks):
    # blocks: list of (start,end) unavailability within [year_start, year_end]
    blocks = [(max(year_start,s), min(year_end,e)) for s,e in blocks]
    blocks = [(s,e) for s,e in blocks if s <= e]
